PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE students (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  school_name TEXT,
  grade TEXT,
  status TEXT DEFAULT '재원',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
, memo TEXT, guardian_name TEXT, guardian_relation TEXT, student_phone TEXT, parent_phone TEXT, student_pin TEXT, target_score INTEGER DEFAULT NULL, planner_exam_date TEXT, high_subjects TEXT, student_address TEXT, vehicle_info TEXT, student_identity_key TEXT, onboarding_started_at TEXT);
CREATE TABLE classes (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  grade TEXT,
  subject TEXT,
  teacher_name TEXT
, schedule_days TEXT, is_active INTEGER DEFAULT 1, textbook TEXT DEFAULT '', day_group TEXT, time_label TEXT, parent_class_id TEXT, promotion_version_id TEXT);
CREATE TABLE class_students (
  class_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  PRIMARY KEY (class_id, student_id)
);
CREATE TABLE attendance (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  status TEXT NOT NULL,
  date DATE NOT NULL,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
, tags TEXT DEFAULT '', memo TEXT DEFAULT '', updated_at TEXT DEFAULT '');
CREATE TABLE homework (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  status TEXT NOT NULL,
  date DATE NOT NULL,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE exam_sessions (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  exam_title TEXT,
  score INTEGER,
  exam_date DATE,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
, question_count INTEGER DEFAULT 0, class_id TEXT, archive_file TEXT, assignment_id TEXT, pack_id TEXT, result_hash TEXT, analysis_status TEXT DEFAULT 'none');
CREATE TABLE wrong_answers (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  session_id TEXT NOT NULL,
  question_id TEXT NOT NULL,
  student_id TEXT NOT NULL
);
CREATE TABLE questions (
  id TEXT PRIMARY KEY,
  standard_unit TEXT,
  difficulty TEXT
);
CREATE TABLE consultations (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  date TEXT NOT NULL,
  type TEXT,
  content TEXT NOT NULL,
  next_action TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE operation_memos (
  id TEXT PRIMARY KEY,
  memo_date TEXT NOT NULL,
  content TEXT NOT NULL,
  is_pinned INTEGER DEFAULT 0,
  is_done INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
, teacher_name TEXT DEFAULT '');
CREATE TABLE exam_schedules (
  id TEXT PRIMARY KEY,
  school_name TEXT NOT NULL,
  grade TEXT,
  exam_name TEXT,
  exam_date TEXT NOT NULL,
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE teachers (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  login_id TEXT UNIQUE NOT NULL,
  password_hash TEXT NOT NULL,
  role TEXT DEFAULT 'teacher',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE teacher_classes (
  teacher_id TEXT NOT NULL,
  class_id TEXT NOT NULL,
  PRIMARY KEY (teacher_id, class_id)
);
CREATE TABLE exam_blueprints (
  archive_file TEXT NOT NULL,
  question_no INTEGER NOT NULL,
  source_archive_file TEXT NOT NULL,
  source_question_no INTEGER NOT NULL,
  standard_unit_key TEXT,
  standard_unit TEXT,
  standard_course TEXT,
  concept_cluster_key TEXT,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT DEFAULT CURRENT_TIMESTAMP, assessment_pack_id TEXT, type_key TEXT, difficulty TEXT,
  PRIMARY KEY (archive_file, question_no)
);
CREATE TABLE class_exam_assignments (
  id TEXT PRIMARY KEY,
  class_id TEXT NOT NULL,
  exam_title TEXT NOT NULL,
  exam_date TEXT NOT NULL,
  question_count INTEGER DEFAULT 0,
  archive_file TEXT DEFAULT '',
  source_type TEXT DEFAULT 'archive',
  created_at TEXT DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT DEFAULT CURRENT_TIMESTAMP, pack_id TEXT, grade_label TEXT, pack_hash TEXT, assignment_batch_id TEXT, target_scope TEXT, created_by TEXT,
  UNIQUE(class_id, exam_title, exam_date, archive_file)
);
CREATE TABLE daily_journals (
  id TEXT PRIMARY KEY,
  date TEXT NOT NULL,
  teacher_name TEXT NOT NULL,
  content TEXT NOT NULL,
  status TEXT DEFAULT '작성중',
  feedback TEXT DEFAULT '',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE class_textbooks (id TEXT PRIMARY KEY, class_id TEXT NOT NULL, title TEXT NOT NULL, status TEXT DEFAULT 'active', start_date TEXT, end_date TEXT, sort_order INTEGER DEFAULT 0, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE class_daily_records (id TEXT PRIMARY KEY, class_id TEXT NOT NULL, date TEXT NOT NULL, teacher_name TEXT, special_note TEXT DEFAULT '', created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, UNIQUE(class_id, date));
CREATE TABLE class_daily_progress (id TEXT PRIMARY KEY, record_id TEXT NOT NULL, class_id TEXT NOT NULL, textbook_id TEXT, textbook_title_snapshot TEXT NOT NULL, progress_text TEXT DEFAULT '', created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE academy_schedules (
  id TEXT PRIMARY KEY,
  schedule_type TEXT NOT NULL,
  title TEXT NOT NULL,
  schedule_date TEXT NOT NULL,
  start_time TEXT,
  end_time TEXT,
  target_scope TEXT DEFAULT 'global',
  student_id TEXT,
  teacher_name TEXT,
  memo TEXT,
  is_closed INTEGER DEFAULT 0,
  is_deleted INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE school_exam_records (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  class_id TEXT,
  school_name TEXT,
  grade TEXT,
  exam_year INTEGER NOT NULL,
  semester TEXT,
  exam_type TEXT NOT NULL,
  subject TEXT NOT NULL,
  score INTEGER,
  target_score_snapshot INTEGER,
  memo TEXT,
  is_deleted INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE student_plans (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  plan_date TEXT NOT NULL,
  title TEXT NOT NULL,
  subject TEXT,
  is_done INTEGER DEFAULT 0,
  repeat_rule TEXT,
  created_at TEXT DEFAULT (datetime('now','localtime')),
  updated_at TEXT DEFAULT (datetime('now','localtime')),
  FOREIGN KEY (student_id) REFERENCES students(id)
);
CREATE TABLE planner_feedback (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  feedback_date TEXT NOT NULL,
  teacher_comment TEXT,
  badge TEXT,
  completion_rate INTEGER,
  created_at TEXT DEFAULT (datetime('now','localtime')),
  updated_at TEXT DEFAULT (datetime('now','localtime')),
  FOREIGN KEY (student_id) REFERENCES students(id)
);
CREATE TABLE homework_photo_assignments (
  id TEXT PRIMARY KEY,
  class_id TEXT NOT NULL,
  teacher_id TEXT NOT NULL,
  title TEXT NOT NULL,
  description TEXT,
  due_date TEXT NOT NULL,
  due_time TEXT,
  status TEXT DEFAULT 'active',
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now')),
  FOREIGN KEY (class_id) REFERENCES classes(id),
  FOREIGN KEY (teacher_id) REFERENCES teachers(id)
);
CREATE TABLE homework_photo_submissions (
  id TEXT PRIMARY KEY,
  assignment_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  is_submitted INTEGER DEFAULT 0,
  submitted_at TEXT,
  synced_homework_date TEXT,
  synced_homework_status TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now')),
  FOREIGN KEY (assignment_id) REFERENCES homework_photo_assignments(id),
  FOREIGN KEY (student_id) REFERENCES students(id),
  UNIQUE(assignment_id, student_id)
);
CREATE TABLE homework_photo_files (
  id TEXT PRIMARY KEY,
  submission_id TEXT NOT NULL,
  file_key TEXT NOT NULL,
  file_name TEXT,
  file_type TEXT,
  file_size INTEGER DEFAULT 0,
  expires_at TEXT NOT NULL,
  deleted_at TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  FOREIGN KEY (submission_id) REFERENCES homework_photo_submissions(id)
);
CREATE TABLE student_enrollments (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  branch TEXT NOT NULL DEFAULT 'apmath',
  class_id TEXT NOT NULL,
  status TEXT DEFAULT 'active',
  start_date TEXT,
  end_date TEXT,
  tuition_amount INTEGER,
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE class_time_slots (
  id TEXT PRIMARY KEY,
  class_id TEXT NOT NULL,
  day_of_week TEXT NOT NULL,
  start_time TEXT NOT NULL,
  end_time TEXT NOT NULL,
  room_name TEXT,
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE timetable_conflict_logs (
  id TEXT PRIMARY KEY,
  conflict_type TEXT NOT NULL,
  target_id TEXT,
  branch_pair TEXT,
  class_a_id TEXT,
  class_b_id TEXT,
  day_of_week TEXT,
  overlap_start TEXT,
  overlap_end TEXT,
  severity TEXT DEFAULT 'warning',
  status TEXT DEFAULT 'open',
  resolved_by TEXT,
  resolved_at TEXT,
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE timetable_conflict_overrides (
  id TEXT PRIMARY KEY,
  conflict_type TEXT NOT NULL,
  target_id TEXT,
  conflict_key TEXT NOT NULL,
  reason TEXT,
  allowed_by TEXT,
  expires_at TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE billing_templates (
  id TEXT PRIMARY KEY,
  branch TEXT DEFAULT 'apmath',
  class_id TEXT,
  name TEXT NOT NULL,
  default_amount INTEGER NOT NULL DEFAULT 0,
  item_type TEXT,
  is_active INTEGER DEFAULT 1,
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE payments (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  billing_run_id TEXT,
  year INTEGER NOT NULL,
  month INTEGER NOT NULL,
  total_amount INTEGER NOT NULL DEFAULT 0,
  paid_amount INTEGER DEFAULT 0,
  due_date TEXT,
  paid_date TEXT,
  status TEXT DEFAULT 'unpaid',
  payment_method TEXT,
  note TEXT,
  invoice_sent_at TEXT,
  receipt_sent_at TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE payment_items (
  id TEXT PRIMARY KEY,
  payment_id TEXT NOT NULL,
  branch TEXT DEFAULT 'apmath',
  enrollment_id TEXT,
  class_id TEXT,
  name TEXT NOT NULL,
  amount INTEGER NOT NULL DEFAULT 0,
  item_type TEXT,
  note TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE billing_adjustments (
  id TEXT PRIMARY KEY,
  payment_id TEXT NOT NULL,
  adjustment_type TEXT NOT NULL,
  name TEXT NOT NULL,
  amount INTEGER NOT NULL DEFAULT 0,
  reason TEXT,
  created_by TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE billing_runs (
  id TEXT PRIMARY KEY,
  year INTEGER NOT NULL,
  month INTEGER NOT NULL,
  branch TEXT DEFAULT 'all',
  status TEXT DEFAULT 'draft',
  total_amount INTEGER DEFAULT 0,
  issued_count INTEGER DEFAULT 0,
  created_by TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  issued_at TEXT,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE parent_contacts (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  name TEXT,
  relation TEXT,
  phone TEXT NOT NULL,
  is_primary INTEGER DEFAULT 1,
  receive_attendance INTEGER DEFAULT 1,
  receive_payment INTEGER DEFAULT 1,
  receive_notice INTEGER DEFAULT 1,
  receive_report INTEGER DEFAULT 1,
  receive_marketing INTEGER DEFAULT 0,
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE message_logs (
  id TEXT PRIMARY KEY,
  student_id TEXT,
  parent_contact_id TEXT,
  branch TEXT,
  message_type TEXT NOT NULL,
  channel TEXT NOT NULL,
  title TEXT,
  content TEXT,
  status TEXT DEFAULT 'pending',
  provider_message_id TEXT,
  error_message TEXT,
  sent_at TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
, recipient_phone_snapshot TEXT, recipient_name_snapshot TEXT, relation_snapshot TEXT, consent_snapshot_json TEXT, template_key TEXT, provider TEXT, preview_batch_id TEXT, queued_at TEXT, delivered_at TEXT, failed_at TEXT, retry_of TEXT);
CREATE TABLE student_status_history (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  old_status TEXT,
  new_status TEXT NOT NULL,
  reason TEXT,
  changed_by TEXT,
  changed_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE class_transfer_history (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  from_class_id TEXT,
  to_class_id TEXT,
  reason TEXT,
  changed_by TEXT,
  changed_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE staff_permissions (
  id TEXT PRIMARY KEY,
  teacher_id TEXT NOT NULL,
  branch TEXT DEFAULT 'all',
  permission_key TEXT NOT NULL,
  allowed INTEGER DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE audit_logs (
  id TEXT PRIMARY KEY,
  actor_id TEXT,
  actor_role TEXT,
  action TEXT NOT NULL,
  target_type TEXT,
  target_id TEXT,
  before_json TEXT,
  after_json TEXT,
  ip_address TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE privacy_access_logs (
  id TEXT PRIMARY KEY,
  actor_id TEXT,
  student_id TEXT,
  access_type TEXT NOT NULL,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE foundation_sync_logs (
  id TEXT PRIMARY KEY,
  sync_type TEXT NOT NULL,
  status TEXT DEFAULT 'success',
  dry_run INTEGER DEFAULT 0,
  inserted_count INTEGER DEFAULT 0,
  skipped_count INTEGER DEFAULT 0,
  updated_count INTEGER DEFAULT 0,
  error_count INTEGER DEFAULT 0,
  summary_json TEXT,
  created_by TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE payment_methods (
  id TEXT PRIMARY KEY,
  method_key TEXT NOT NULL UNIQUE,
  name TEXT NOT NULL,
  category TEXT NOT NULL,
  is_active INTEGER DEFAULT 1,
  sort_order INTEGER DEFAULT 0,
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE payment_transactions (
  id TEXT PRIMARY KEY,
  payment_id TEXT,
  student_id TEXT NOT NULL,
  branch TEXT DEFAULT 'apmath',
  transaction_type TEXT NOT NULL DEFAULT 'payment',
  method_key TEXT NOT NULL,
  amount INTEGER NOT NULL DEFAULT 0,
  transaction_date TEXT NOT NULL,
  status TEXT DEFAULT 'completed',
  receipt_no TEXT,
  external_provider TEXT,
  external_transaction_id TEXT,
  note TEXT,
  created_by TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE cashbook_entries (
  id TEXT PRIMARY KEY,
  entry_date TEXT NOT NULL,
  entry_type TEXT NOT NULL,
  category TEXT NOT NULL,
  branch TEXT DEFAULT 'all',
  amount INTEGER NOT NULL DEFAULT 0,
  payment_transaction_id TEXT,
  student_id TEXT,
  title TEXT NOT NULL,
  description TEXT,
  method_key TEXT,
  created_by TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
, status TEXT DEFAULT 'active', is_active INTEGER DEFAULT 1);
CREATE TABLE refund_records (
  id TEXT PRIMARY KEY,
  payment_id TEXT,
  payment_transaction_id TEXT,
  student_id TEXT NOT NULL,
  branch TEXT DEFAULT 'apmath',
  refund_amount INTEGER NOT NULL DEFAULT 0,
  refund_method_key TEXT,
  refund_date TEXT NOT NULL,
  reason TEXT,
  status TEXT DEFAULT 'completed',
  created_by TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE carryover_records (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  from_payment_id TEXT,
  to_payment_id TEXT,
  branch TEXT DEFAULT 'apmath',
  amount INTEGER NOT NULL DEFAULT 0,
  carryover_type TEXT NOT NULL DEFAULT 'credit',
  reason TEXT,
  status TEXT DEFAULT 'active',
  created_by TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE billing_policy_rules (
  id TEXT PRIMARY KEY,
  rule_key TEXT NOT NULL,
  branch TEXT DEFAULT 'all',
  rule_type TEXT NOT NULL,
  name TEXT NOT NULL,
  value_json TEXT,
  is_active INTEGER DEFAULT 1,
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE accounting_daily_summaries (
  id TEXT PRIMARY KEY,
  summary_date TEXT NOT NULL,
  branch TEXT DEFAULT 'all',
  total_billed INTEGER DEFAULT 0,
  total_paid INTEGER DEFAULT 0,
  total_refunded INTEGER DEFAULT 0,
  total_discount INTEGER DEFAULT 0,
  total_outstanding INTEGER DEFAULT 0,
  by_method_json TEXT,
  by_category_json TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE accounting_monthly_summaries (
  id TEXT PRIMARY KEY,
  year INTEGER NOT NULL,
  month INTEGER NOT NULL,
  branch TEXT DEFAULT 'all',
  total_billed INTEGER DEFAULT 0,
  total_paid INTEGER DEFAULT 0,
  total_refunded INTEGER DEFAULT 0,
  total_discount INTEGER DEFAULT 0,
  total_outstanding INTEGER DEFAULT 0,
  by_method_json TEXT,
  by_category_json TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE study_materials (
  id TEXT PRIMARY KEY,
  material_type TEXT NOT NULL,
  title TEXT NOT NULL,
  grade TEXT,
  semester TEXT,
  subject TEXT DEFAULT '수학',
  numbering_type TEXT DEFAULT 'global',
  number_start INTEGER,
  number_end INTEGER,
  status TEXT DEFAULT 'active',
  created_by TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE material_unit_ranges (
  id TEXT PRIMARY KEY,
  material_id TEXT NOT NULL,
  unit_order INTEGER DEFAULT 0,
  unit_text TEXT NOT NULL,
  subunit_text TEXT,
  start_no INTEGER NOT NULL,
  end_no INTEGER NOT NULL,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(material_id, start_no, end_no)
);
CREATE TABLE material_question_tags (
  id TEXT PRIMARY KEY,
  material_id TEXT NOT NULL,
  question_no INTEGER NOT NULL,
  unit_text TEXT,
  type_text TEXT,
  tags TEXT,
  difficulty TEXT,
  page_no TEXT,
  memo TEXT,
  needs_review INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(material_id, question_no)
);
CREATE TABLE class_material_assignments (
  id TEXT PRIMARY KEY,
  class_id TEXT NOT NULL,
  material_id TEXT NOT NULL,
  assignment_title TEXT,
  assigned_date TEXT NOT NULL,
  status TEXT DEFAULT 'active',
  created_by TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE student_material_submissions (
  id TEXT PRIMARY KEY,
  assignment_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  is_submitted INTEGER DEFAULT 0,
  is_no_wrong INTEGER DEFAULT 0,
  submitted_at TEXT,
  status TEXT DEFAULT 'active',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(assignment_id, student_id)
);
CREATE TABLE student_material_wrong_answers (
  id TEXT PRIMARY KEY,
  submission_id TEXT NOT NULL,
  assignment_id TEXT NOT NULL,
  material_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  class_id TEXT,
  teacher_id TEXT,
  grade TEXT,
  wrong_date TEXT NOT NULL,
  question_no INTEGER NOT NULL,
  status TEXT DEFAULT 'active',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE teacher_sessions (
  id TEXT PRIMARY KEY,
  teacher_id TEXT NOT NULL,
  login_id TEXT,
  session_token TEXT NOT NULL UNIQUE,
  expires_at TEXT NOT NULL,
  revoked_at TEXT,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP,
  last_used_at TEXT
);
CREATE TABLE parent_contact_consents (
  id TEXT PRIMARY KEY,
  parent_contact_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  branch TEXT DEFAULT 'all',
  consent_type TEXT NOT NULL,
  is_allowed INTEGER DEFAULT 1,
  changed_by TEXT,
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(parent_contact_id, student_id, branch, consent_type)
);
CREATE TABLE timetable_versions (
  id TEXT PRIMARY KEY,
  school_year INTEGER NOT NULL,
  title TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'draft',
  source_version_id TEXT,
  effective_from TEXT,
  effective_to TEXT,
  created_by TEXT,
  activated_at TEXT,
  archived_at TEXT,
  cancelled_at TEXT,
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE timetable_version_slots (
  id TEXT PRIMARY KEY,
  version_id TEXT NOT NULL,
  class_id TEXT NOT NULL,
  day_of_week TEXT NOT NULL,
  start_time TEXT NOT NULL,
  end_time TEXT NOT NULL,
  room_name TEXT,
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
, version_class_id TEXT, source_class_id TEXT);
CREATE TABLE timetable_version_student_assignments (
  id TEXT PRIMARY KEY,
  version_id TEXT NOT NULL,
  class_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  student_name_snapshot TEXT,
  source_class_id TEXT,
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, version_class_id TEXT, source_grade TEXT, next_grade TEXT, excluded_reason TEXT, temp_student_id TEXT, student_snapshot TEXT,
  UNIQUE(version_id, student_id)
);
CREATE TABLE timetable_version_classes (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL DEFAULT 'apmath',
  version_id TEXT NOT NULL,
  source_class_id TEXT,
  name_snapshot TEXT,
  source_name TEXT,
  grade_snapshot TEXT,
  source_grade TEXT,
  next_grade TEXT,
  teacher_name_snapshot TEXT,
  subject_snapshot TEXT,
  schedule_days_snapshot TEXT,
  time_label_snapshot TEXT,
  status TEXT NOT NULL DEFAULT 'draft',
  excluded_reason TEXT,
  is_new INTEGER NOT NULL DEFAULT 0,
  sort_order INTEGER NOT NULL DEFAULT 0,
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE timetable_version_new_students (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL DEFAULT 'apmath',
  version_id TEXT NOT NULL,
  version_class_id TEXT,
  temp_student_id TEXT,
  name_snapshot TEXT NOT NULL,
  school_name_snapshot TEXT,
  grade_snapshot TEXT,
  next_grade TEXT,
  phone_snapshot TEXT,
  memo TEXT,
  status TEXT NOT NULL DEFAULT 'draft',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE timetable_version_apply_logs (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL DEFAULT 'apmath',
  version_id TEXT NOT NULL,
  status TEXT NOT NULL,
  started_at TEXT,
  finished_at TEXT,
  error_message TEXT,
  summary_json TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE onboarding_tasks (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  class_id TEXT,
  enrollment_id TEXT,
  teacher_id TEXT,
  created_teacher_id TEXT,
  task_type TEXT NOT NULL,
  task_order INTEGER NOT NULL DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'pending',
  onboarding_started_at TEXT NOT NULL,
  visible_from TEXT NOT NULL,
  due_date TEXT NOT NULL,
  deferred_until TEXT,
  completed_at TEXT,
  completed_by TEXT,
  completed_consultation_id TEXT,
  contact_method TEXT,
  last_contact_at TEXT,
  notes TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(student_id, enrollment_id, task_type)
);
CREATE TABLE eie_import_sessions (
  id TEXT PRIMARY KEY,
  file_name TEXT NOT NULL,
  sheet_name TEXT NOT NULL,
  source_month TEXT NOT NULL,
  imported_at TEXT,
  status TEXT NOT NULL DEFAULT 'imported',
  raw_meta_json TEXT,
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(sheet_name, source_month)
);
CREATE TABLE eie_timetable_cells (
  id TEXT PRIMARY KEY,
  import_session_id TEXT NOT NULL,
  day_label TEXT,
  period_label TEXT NOT NULL,
  period_order INTEGER,
  start_time TEXT,
  end_time TEXT,
  class_name_raw TEXT,
  teacher_name_raw TEXT,
  room_raw TEXT,
  column_index INTEGER NOT NULL,
  student_count INTEGER DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'imported',
  raw_meta_json TEXT,
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, source_type TEXT NOT NULL DEFAULT 'import', source_import_session_id TEXT, memo TEXT,
  FOREIGN KEY (import_session_id) REFERENCES eie_import_sessions(id) ON DELETE CASCADE,
  UNIQUE(import_session_id, day_label, period_label, column_index)
);
CREATE TABLE eie_students (
  id TEXT PRIMARY KEY,
  display_name TEXT NOT NULL,
  normalized_name TEXT NOT NULL,
  grade TEXT,
  status TEXT DEFAULT 'active',
  source_type TEXT DEFAULT 'candidate',
  source_import_session_id TEXT,
  source_cell_id TEXT,
  memo TEXT,
  raw_meta_json TEXT,
  created_by TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE eie_student_contacts (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  phone TEXT NOT NULL,
  normalized_phone TEXT NOT NULL,
  contact_label TEXT,
  is_primary INTEGER DEFAULT 1,
  source_type TEXT DEFAULT 'candidate',
  source_import_session_id TEXT,
  source_cell_id TEXT,
  memo TEXT,
  raw_meta_json TEXT,
  created_by TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(student_id, normalized_phone)
);
CREATE TABLE eie_student_schedule_assignments (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  timetable_cell_id TEXT NOT NULL,
  status TEXT DEFAULT 'active',
  source_type TEXT DEFAULT 'candidate',
  source_import_session_id TEXT,
  memo TEXT,
  raw_meta_json TEXT,
  created_by TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(student_id, timetable_cell_id)
);
CREATE TABLE public_inquiries (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  source TEXT NOT NULL DEFAULT 'wangji_public_home',
  parent_name TEXT NOT NULL,
  phone TEXT NOT NULL,
  phone_digits TEXT,
  student_grade TEXT,
  interest TEXT,
  message TEXT,
  status TEXT NOT NULL DEFAULT 'new',
  handled_at TEXT,
  handled_by TEXT,
  memo TEXT,
  ip_hash TEXT,
  user_agent TEXT
);
CREATE TABLE assessment_result_items (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  session_id TEXT NOT NULL,
  assignment_id TEXT,
  pack_id TEXT,
  student_id TEXT,
  class_id TEXT,
  order_no INTEGER NOT NULL,
  question_no INTEGER,
  result_status TEXT DEFAULT 'unchecked'
    CHECK (result_status IN ('correct', 'wrong', 'partial', 'unchecked')),
  is_correct INTEGER
    CHECK (is_correct IN (0, 1) OR is_correct IS NULL),
  student_answer TEXT,
  correct_answer TEXT,
  score REAL,
  max_score REAL,
  source_archive_file TEXT,
  source_question_no INTEGER,
  standard_unit_key TEXT,
  standard_unit TEXT,
  concept_cluster_key TEXT,
  type_key TEXT,
  difficulty TEXT,
  analysis_note TEXT,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE assessment_analysis_snapshots (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  academy_id TEXT,
  session_id TEXT,
  assignment_id TEXT,
  pack_id TEXT,
  student_id TEXT,
  class_id TEXT,
  grade_label TEXT,
  analysis_scope TEXT
    CHECK (analysis_scope IN ('student', 'class', 'grade') OR analysis_scope IS NULL),
  analysis_type TEXT
    CHECK (analysis_type IN ('raw_item_analysis', 'unit_summary', 'class_summary', 'grade_summary') OR analysis_type IS NULL),
  source_hash TEXT NOT NULL,
  analysis_json TEXT NOT NULL,
  source_summary_json TEXT,
  created_by TEXT,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT DEFAULT CURRENT_TIMESTAMP,
  invalidated_at TEXT,
  is_stale INTEGER DEFAULT 0
    CHECK (is_stale IN (0, 1))
);
CREATE TABLE assessment_report_snapshots (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  academy_id TEXT,
  analysis_snapshot_id INTEGER,
  session_id TEXT,
  assignment_id TEXT,
  pack_id TEXT,
  student_id TEXT,
  class_id TEXT,
  grade_label TEXT,
  report_type TEXT
    CHECK (report_type IN ('premium_analysis', 'parent_report', 'printable_report') OR report_type IS NULL),
  source_hash TEXT NOT NULL,
  report_json TEXT NOT NULL,
  rendered_html TEXT,
  ai_source TEXT,
  ai_model TEXT,
  created_by TEXT,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT DEFAULT CURRENT_TIMESTAMP,
  invalidated_at TEXT,
  is_stale INTEGER DEFAULT 0
    CHECK (is_stale IN (0, 1))
);
CREATE TABLE planner_study_sessions (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  plan_id TEXT,
  subject TEXT,
  status TEXT DEFAULT 'active',
  started_at TEXT NOT NULL,
  paused_at TEXT,
  ended_at TEXT,
  duration_seconds INTEGER DEFAULT 0,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE ap_timetable_month_snapshots (
  id TEXT PRIMARY KEY,
  month_key TEXT NOT NULL,
  snapshot_date TEXT NOT NULL,
  title TEXT,
  status TEXT NOT NULL DEFAULT 'active',
  source_type TEXT NOT NULL DEFAULT 'manual',
  source_hash TEXT,
  memo TEXT,
  created_by TEXT,
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(month_key, snapshot_date)
);
CREATE TABLE ap_timetable_month_snapshot_cells (
  id TEXT PRIMARY KEY,
  snapshot_id TEXT NOT NULL,
  source_cell_id TEXT,
  source_class_id TEXT,
  day_label TEXT,
  period_label TEXT,
  period_order INTEGER,
  start_time TEXT,
  end_time TEXT,
  class_name TEXT,
  teacher_id TEXT,
  teacher_name TEXT,
  room TEXT,
  subject TEXT,
  grade TEXT,
  student_count INTEGER DEFAULT 0,
  memo TEXT,
  raw_meta_json TEXT,
  sort_order INTEGER DEFAULT 0,
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY(snapshot_id) REFERENCES ap_timetable_month_snapshots(id) ON DELETE CASCADE
);
CREATE TABLE ap_timetable_month_snapshot_students (
  id TEXT PRIMARY KEY,
  snapshot_id TEXT NOT NULL,
  snapshot_cell_id TEXT NOT NULL,
  source_student_id TEXT,
  source_class_id TEXT,
  display_name TEXT,
  grade TEXT,
  school_name TEXT,
  student_status TEXT,
  enrollment_date TEXT,
  discharged_at TEXT,
  raw_meta_json TEXT,
  sort_order INTEGER DEFAULT 0,
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY(snapshot_id) REFERENCES ap_timetable_month_snapshots(id) ON DELETE CASCADE,
  FOREIGN KEY(snapshot_cell_id) REFERENCES ap_timetable_month_snapshot_cells(id) ON DELETE CASCADE
);
CREATE TABLE student_report_archives (
