INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1777248710057','s01','2026-04-24','출결','이모집 가느라 결석','보강요일 정해야됨','2026-04-27 00:11:50');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1777870960742','s12','2026-05-04','성적',replace('목요일 시험 후 연락두절, 전화 받지 않고 시험지도 안 가져온 상황\n어미님과 통화내용.\n시험시간이 부족해서 시험을 못 봤다는 설명을 들음. 지난 기말고사 때도 같은 문제로 성적이 안 나왔다고 했는데, 이번에도 같은 문제로 인해 성적이 안나왔다고 하니, 어머님이 그 부분에 대해 대비를 했는지 물어보셔서, 기출문제 풀고 모의고사 풀 때 시간이 부족한 적은 없었다. 항상 시간내에 풀었고, 시험시간에 주의해야 할 부분 자주 이야기하고 시험보러 간 상황이라고 말씀드림.\n월요일에 수업시간에 시험지 같이 보내주시기로 하시고, 분석 후 다시 연락드리기로함.','\n',char(10)),'','2026-05-04 05:02:40');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1777871085208','s13','2026-05-04','성적','시간이 부족해서 서술형 문제를 마무리하지 못하고 채점에서 객관식 틀린 것까지 생각하면 77점 정도 예상된다고 안내. 예전보다 나아졌지만 숙제과정에서 어렵거나 하기 싫은 부분을 건너뛰고 쉬운 것만 해결하는 습관이 아직도 개선되지 않음을 말씀드림. 월요일 등원 안내 드리고 상담 종료','','2026-05-04 05:04:45');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1777871343836','s16','2026-05-04','성적','유준이가 학원에 온 후 2주만에 시험을 봤지만, 기초가 너무 부족해 시험준비를 거의 하지 않고 초등학교 5학년 분수 계산부터 연습했음을 안내. 기말고사 과정 때 부족한 부분을 채워나가면 진도를 진행하겠지만 스스로 하려고 하지 않으면 개선되기 힘들기 때문에 보강관리 철저히 하겠다고 안내','','2026-05-04 05:09:03');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1777873628541','s14','2026-05-04','성적',replace('중간고사 후 상담\n시험성적이 많이 오르긴 했는데, 더 잘 볼 수 있었을 것 같은 아쉬움이 있다고, 현성이가 시험에, 특히 수학에 실수가 많음을 이야기함. 현성이의 학습 태도와 성적의 변화에 대해 논의하며 앞으로 실수하지 않도록 그 부분 더 신경쓰기로 말씀드림.','\n',char(10)),'','2026-05-04 05:47:08');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1777873689891','s15','2026-05-04','기타',replace('가족여행으로 결석-아직 중간고사 시험지를 못 받은 상황, 가채점은 70점 중반정도 나올 것 같다고 이야기함.\n시험지 확인 후 학부모 상담예정','\n',char(10)),'수요일 등원 시 보강 예정','2026-05-04 05:48:09');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1778067602011','s16','2026-05-06','태도','숙제를 하나도 안해서, 이대로 계속하면 학원 다닐 필요가 없지 안냐고 말씀드림.','','2026-05-06 11:40:02');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1778332648744','seed_kj_ttf_p3_04','2026-05-08','학습','성적관련상담+결석&보충안내','','2026-05-09 13:17:28');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1778332689357','seed_kj_mwf_p1_04','2026-05-08','학습','결석 보충안내','','2026-05-09 13:18:09');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1778651177056','seed_kj_ttf_p1_04','2026-05-13','학습',replace('60->92 성적 많이 상승한 부분 언급했으나 크게 만족은 못하심.\n\n+ 고등 언니 수학 점수 관련. 점수 50점대이나 정보가 부족하여 점수가 왜 그런지에 대한 인지 부족. 3년째 언급한 부분이지만 계속 언급해야할듯. 예를들어 순여 고2 1등급컷이 55점임을 말씀드림. 와닿지는 않으신듯. 아직 등급컷이 안나와 확실치는 않으나 60등 안으로 들어오긴 힘들 것 같다고 말씀드림. 등급 부분에 대한 개념이 충분치 않으신듯.','\n',char(10)),'','2026-05-13 05:46:17');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1779190775253','s_1779190694551','2026-05-19','기타',replace('신입상담\n수업 진행 상황: 학생(지훈)은 수학적 재능이 있어 선생님의 설명을 잘 이해하고 문제를 해결하는 능력이 보인다\n​보강 필요성: 현재 진도가 학원 진도에 비해 뒤처져 있고, 1학기 과정을 마무리해야 하므로 보강이 필요합니다.\n​향후 계획: 1개월에서 1개월 반 정도의 보강 기간이 소요될 것으로 예상되며, 다른 학원 수업(영어 등)과 겹치지 않게 시간을 조율하여 진도를 맞출 예정입니다.','\n',char(10)),'','2026-05-19 11:39:35');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1779262488350','s05','2026-05-20','학습',replace('진후는 현재 중1 2학기 진도를 진행하면서 중1 1학기 내용을 함께 복습 중임. 이전 학원에서 1학기 내용이 충분히 정리되지 않은 상태로 온 부분이 있어, 뒤로 갈수록 어려워하거나 부담을 느끼는 모습이 관찰됨. 이에 방학 전까지 부족한 부분을 보완하기 위해 주 1회 정도 추가 보강을 진행하기로 안내드림.\n\n보강은 월요일 또는 수요일 중 가능한 날에 진행할 예정이며, 현재는 수요일 학교 후 보강을 진행 중임. 어머님께는 학습 보완이 필요한 상황과 함께, 학생이 지치지 않도록 가정에서도 컨디션을 살펴봐 주시길 부탁드림. 어머님께서 보강 진행에 동의하셨고, 학습적인 부분은 학원에서 책임감을 가지고 더 신경 쓰겠다고 말씀드림.','\n',char(10)),'','2026-05-20 07:34:48');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1779299162744','seed_kj_ttf_p2_01','2026-05-20','학습','도형을 많이 어려워해서 걱정입니다. 매 학년마다 2학기 부분은 전체 도형으로만 이루어져 있어서 예서에게 숨쉴 구멍 없는 학기가 될 것 같습니다. 다행히 1학기 부분은 잘 학습되어 있어서 학교에서도 좋은 성과를 얻고 있지만 앞으로 2학기 부분에 계속 어려움을 겪을 것 같습니다.','도형은 항상 다양한 모양이 나오므로 일단 공식을 잘 암기 시킨 후 많은 유형을 풀이할 수 있도록 진행하도록 하겠습니다.','2026-05-20 17:46:02');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1779331064134','s23','2026-05-21','학습',replace('박정원 학생은 상습적인 과제 미이행으로 인해 학원에 남아 보충 학습을 하거나 야간 및 주말에 추가 등원하는 일이 반복되고 있습니다. 학생은 1학년 때부터 이러한 방식에 익숙해진 탓인지, 밤 10시나 11시까지 학원에 머무는 것에 대해 별다른 거부감이나 경각심을 느끼지 않는 무던한 태도를 보이고 있습니다 [1, 2].\n\n학부모님께서는 학생이 스스로 숙제를 해결하지 않는 모습에 답답함을 느끼시면서도, 직접 훈계할 경우 자녀와의 관계가 악화될 것을 우려하고 계십니다. 따라서 학원 측에서 학생을 엄격하게 관리하고 숙제 이행에 대해 지속적으로 당부해 줄 것을 요청하셨습니다.\n이번 주 금요일에는 학부모님의 개인 일정으로 인해 정원이가 영어 수업 종료 후 즉시 본원으로 등원하여 미진한 학습을 완료하기로 협의하였습니다. 오늘 학생이 등원하면 해당 내용을 직접 전달하고 금요일 일정에 대한 확답을 받아 지도할 계획입니다.','\n',char(10)),'','2026-05-21 02:37:44');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1779341941873','s25','2026-05-13','성적',replace('현욱이가 이번 시험에서 **78점**을 기록했으나, 이는 실력 부족보다는 **왕운중** 시험의 난이도가 급격히 상승한 것이 주요 원인으로 보입니다. 현재 학교 전체 만점자가 5~6명에 불과하고 원내에서도 90점 이상 득점자가 거의 없을 정도로 변별력이 매우 컸던 시험이었습니다. 평소 원내 평가에서 95~100점을 유지해 온 현욱이의 실력을 고려할 때, 이번 결과는 학교 시험의 높은 난이도 때문으로 판단됩니다.\n\n현욱이는 수업 중 문제 풀이 속도가 매우 빠르고 성취도가 우수하여 상급 반 이동을 고려할 정도로 뛰어난 역량을 갖추고 있습니다. 이번 점수는 고등학교 5등급제 기준으로 보아도 **2등급 이내**에 해당하는 수준이며, 일반적인 난이도의 시험이었다면 충분히 상욱권에 해당합니다. 따라서 현욱이가 결과에 위축되지 않도록 가정에서도 많은 격려가 필요한 시점입니다.\n\n기말고사의 핵심인 **함수 단원**은 출제 난이도가 더욱 높을 것으로 예상되어, 고등학교 모의고사 문제 등 **심화 자료를 활용한 대비**를 진행할 계획입니다. 현욱이가 이전에 함수 파트를 다소 어려워했던 점을 반영하여 기초부터 심화까지 다시 한번 꼼꼼하게 복습을 진행하겠습니다. 학교의 높은 출제 경향에 잘 적응하여 다음 시험에서는 현욱이의 실제 실력이 성과로 이어질 수 있도록 최선을 다해 지도하겠습니다.','\n',char(10)),'','2026-05-21 05:39:01');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1779448499970','s16','2026-05-22','학습',replace('유준 학생은 현재 수학 학습량이 매우 부족하며, 스스로 문제를 해결하려는 의지가 거의 없는 상태입니다. 한 달 넘게 지도했음에도 불구하고 손으로 직접 식을 써서 푸는 습관이 전혀 잡히지 않아 기초적인 사칙연산조차 어려워하고 있으며, 모르는 문제가 나오면 스스로 생각하기보다 즉시 질문하거나 아예 포기해 버리는 태도를 보이고 있습니다.\n\n과제를 내주어도 정답률이 20% 미만으로 매우 낮고, 단순히 문제를 그대로 옮겨 적어오는 등 학습에 집중하지 못하는 상황입니다. 특히 교사가 옆에서 지켜보지 않으면 펜을 놓고 멍하게 있는 등 타성에 젖어 있어, 학원 측에서는 유준이의 학습 습관을 근본적으로 바꾸기 위한 특단의 조치가 필요하다고 판단하고 있습니다.\n\n이에 따라 복싱 등 다른 일정을 조정하여 매일 학원에서 3~4시간씩 교사의 밀착 감독 하에 ''앉아서 손가락을 움직이는 습관''부터 다시 기르기로 협의하였습니다. 학부모님께서도 유준이가 수학을 완전히 포기하지 않도록 가정에서 협조해 주시기로 하셨으며, 화요일과 목요일에도 영어 수업이 끝나는 대로 즉시 등원시켜 엄격하게 관리 지도를 진행할 계획입니다.','\n',char(10)),'','2026-05-22 11:14:59');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1779889955438','s_1779524626507_uu11vv','2026-05-27','학습',replace('1. 신규로 오고 전부 다 배웠다길래, 라이트쎈 등식의성질과 방정식풀이에 대한오답이 너무많음.\n2.개념유형라이트로 연산위주 과제로 바꿈\n3.그래도 오답이많고, 숙제 고치는데에 시간을 다씀','\n',char(10)),'다른요일 보강하려 했으나, 영어가 있어서 그렇게는 힘들것같고, 연락만 주면 데리러 가겠으니, 조금 더 남겨서 시키는 쪽으로 진행하기로 함.','2026-05-27 13:52:35');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1780279609678','s_1779190694551','2026-05-29','학습',replace('지훈이가 일주일간의 적응 기간을 무사히 마치고 6월부터 정식으로 수업을 시작하게 되었습니다. 현재 화요일, 목요일, 금요일 정규 수업 외에도 다른 학생들과의 진도 차이를 메우기 위해 수요일마다 추가로 등원하여 1학년 1학기 과정을 마무리하고 2학기 진도를 보충하는 중입니다.\n지훈이는 기본적인 수학적 감각이 좋아 머지않아 진도를 충분히 따라올 것으로 보이며, 현재는 학원 적응 및 교사와 신뢰 관계를 쌓는 데 집중하고 있습니다. 앞으로는 점진적으로 숙제량을 늘려가며 매일 학습하는 습관을 기르고, 장시간 집중해서 앉아 있는 연습을 통해 기초 학습 체력을 다지는 데 주력할 계획입니다.','\n',char(10)),'','2026-06-01 02:06:49');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1780280060504','s08','2026-05-29','학습',replace('지우가 복통으로 인해 오늘 수업에 결석하게 되었습니다. 약을 복용해야 할 정도로 상태가 좋지 않아 가정에서 휴식을 취하며 안정을 취하기로 하였습니다.\n\n내일 오전 11시에는 지혁이의 보충 수업이 예정되어 있어, 지우의 컨디션이 회복되는 대로 두 학생을 함께 등원시켜 주시기로 어머님과 협의를 마쳤습니다. 지우의 건강 상태를 확인하여 내일 지혁이와 함께 보충 학습에 성실히 참여할 수 있도록 지도하겠습니다.','\n',char(10)),'','2026-06-01 02:14:20');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1780542684473','s21','2026-06-04','학습',replace('채민이 어머니께 연락드려 오늘 반 친구들 대부분이 순천대학교 축제 참석으로 결석 예정이라, 채민이도 오늘은 쉬고 반 전체 보강을 추후 별도로 잡아 진행하기로 안내함.\n\n최근 왕운중 수학 시험이 전반적으로 어렵게 출제되고 있으며, 학교 평균도 낮아진 상황을 설명드림. 특히 중간에 고난도 문항이 배치되어 학생들이 체감 난도가 높았고, 앞으로는 학교 출제 경향에 맞춰 고등 모의고사 유형까지 포함해 대비를 강화할 예정임.\n\n어머니께서는 채민이가 수학에 조금 더 욕심을 가졌으면 한다고 말씀하심. 이에 현재 시점에서 지나친 부담보다는 영수 기본기를 유지하면서 고등 진학 전 겨울방학부터 집중적으로 끌어올리는 방향이 중요하다고 안내함. 고등 진학 후 첫 시험 대비가 중요하므로 이후 학습 태도와 욕심을 조금씩 잡아가기로 함.','\n',char(10)),'','2026-06-04 03:11:24');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1780564348805','s_1780553452245_q7ekta','2026-06-04','기타',replace('신입상담\n시범수업 후 담임인사.\n홍이가 자기 수준을 알고 공부를 열심히 하는 계기가 생기면 좋겠다고 하심','\n',char(10)),'','2026-06-04 09:12:28');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781245700987','s16','2026-06-12','학습',replace('유준이 수업은 개인 일정으로 오늘 진행이 어려워 내일 보강으로 조정 안내함. 내일 11시 또는 1시 중 보강 가능하며, 유준이는 1시에 오면 더 집중해서 봐줄 수 있어 1시 보강으로 안내함.\n\n최근 방정식 기본 문제는 어느 정도 풀기 시작했고, 예전보다 수학 학원에서 집중해서 해야 한다는 마음이 조금씩 생기는 모습이 보임. 아직 완전히 잡힌 상태는 아니지만, 기본 문제를 풀 수 있다는 자신감부터 만들어 50점 이상을 1차 목표로 지도하기로 함.\n\n어머니께서는 유준이가 못할 것 같으면 아예 포기하는 성향이 있어 걱정된다고 말씀하셨고, 앞으로 옆에서 끝까지 붙잡고 마라톤처럼 꾸준히 지도해 보기로 상담함.','\n',char(10)),'','2026-06-12 06:28:21');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781245960129','s13','2026-06-12','학습',replace('도현이 어머니께 연락드려 시험 대비가 시작되어 주말 보강 등을 통해 준비를 진행할 예정이라고 안내함. 도현이는 2학년이 되면서 예전보다 스스로 소통도 잘하고, 수업 적응도 안정적으로 되고 있음.\n\n오늘 수업은 개인 일정으로 진행이 어려워 내일 11시 보강으로 변경 안내함. 도현이에게도 연락하여 가능 여부 확인했고, 어머니께 내일 11시에 등원하도록 안내함.\n\n시험 대비 기간에는 영어 보강 등 일정이 겹쳐 시간이 넉넉하지는 않지만, 가능한 범위에서 추가 지도를 통해 점수를 조금씩 끌어올릴 수 있도록 준비하기로 함.','\n',char(10)),'','2026-06-12 06:32:40');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781591199103','s04','2026-06-16','학습',replace('다희 어머니께 연락드려 현재 1학년 1학기 교재는 거의 마무리되었고, 1학년 2학기도 마지막 단원 정도 남아 있어 이후 커리큘럼을 안내함. 다음 주쯤부터 2학년 1학기 새 교재와 1학년 2학기 복습 교재를 병행할 예정이며, 방학 중 1학년 2학기 내용을 한 번 더 정리하고 이후 추가 복습 및 시험 대비까지 이어갈 계획임.\n\n다희는 전반적으로 성실하고 이해력도 좋으며, 처음 보는 문제를 고민하는 힘이 좋은 편이라고 안내함. 다만 도형 단원은 입체적으로 받아들이는 데 시간이 걸리고, 궁금한 부분을 끝까지 이해하려는 성향이 강해 학습 속도가 다소 느린 편임. 이 부분은 장점이기도 하지만 시험 상황에서는 한 문제에 오래 멈추지 않고 아는 문제부터 풀고 넘어가는 연습이 필요하다고 상담함.\n\n어머니께서는 다희가 숙제 시간이 오래 걸리고 최근 사춘기 기미가 있어 말하기 조심스럽다고 말씀하심. 이에 아직 학습적으로 큰 문제는 없으며, 앞으로는 “지금 꼭 알아야 할 것”과 “나중에 더 깊게 볼 것”을 구분하며 넘어가는 연습, 시험 시간 관리 습관을 꾸준히 지도하기로 함. AI 활용은 답만 베끼는 방식이 아니라 모르는 지점을 설명받는 보조 도구로 조심스럽게 활용하도록 안내함.','\n',char(10)),'','2026-06-16 06:26:39');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781591363925','s_1779190694551','2026-06-16','1개월 상담',replace('지훈이 어머니께 연락드려 학원 적응 상황을 상담함. 등원한 지 약 한 달 정도 되었고, 도형 단원에서 이해력과 풀이가 좋아 칭찬을 많이 해주고 있으며 본인도 자신감을 얻고 있는 모습이라고 안내함.\n\n어머니께서는 기존 학원에서 잘한다는 이야기를 많이 들어 기대가 있었으나, 이번 진단평가 결과에 다소 실망이 있었다고 말씀하심. 이에 진단평가는 최상위권 선별을 위해 일부러 어렵게 출제되는 편이며, 지훈이는 현재 모습으로 볼 때 충분히 잘할 수 있는 학생이라고 설명드림.\n\n현재 1학년 2학기 앞부분 보완이 필요해 수요일 추가 학습을 진행할 예정이며, 다음 주부터 2학년 1학기 과정도 들어갈 예정임. 지훈이는 보강이 필요하다고 하면 거부감 없이 잘 참여하는 편이라, 앞으로도 적응 상황과 학습 흐름을 지켜보며 지도하기로 함.','\n',char(10)),'','2026-06-16 06:29:23');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781592403701','s01','2026-06-16','학습',replace('세아 어머니께 연락드려 현재 1학년 1학기 복습 교재는 거의 마무리되어, 이후 1학년 2학기 복습으로 바로 들어갈 예정이라고 안내함. 1학년 2학기 진도 교재도 마지막 단원 정도 남아 있어, 마무리 후 2학년 1학기 새 교재도 병행할 계획임.\n\n세아는 계산 쪽은 비교적 잘 따라오지만, 도형 단원에서 입체감이나 선·면을 파악하는 부분을 다소 어려워하는 모습이 있어 복습 교재를 통해 더 정확히 잡아가기로 함. 오답은 많더라도 고치는 과정은 잘하고 있어, 시험 전까지 반복 학습을 통해 3~4회 이상 정리할 예정임.\n\n어머니께서는 세아가 집에서도 도형을 어려워하지만 혼잣말을 하며 풀어보려는 모습이 있고, 가끔 집중이 흐트러져 아는 것도 틀린다고 말씀하심. 앞으로 활용 문제 읽기와 식 세우기 연습을 꾸준히 진행하고, AI는 답을 베끼는 방식이 아니라 모르는 부분을 설명받는 보조 도구로 조심스럽게 활용하도록 안내함.','\n',char(10)),'','2026-06-16 06:46:43');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781593135629','s03','2026-06-16','학습',replace('수인이 어머니께 연락드려 학습 상황과 커리큘럼을 안내함. 수인이는 현재 수업에서 매우 잘 따라오고 있으며, 대수뿐 아니라 도형 단원도 빠르고 정확하게 풀어내는 편이라 수학적 역량이 좋은 학생으로 판단된다고 말씀드림.\n\n어머니께서는 집에서 말이 많지 않고 공부하는 모습이 잘 보이지 않아 걱정하셨으나, 학원에서는 필요한 의사표현을 하고 문제 풀이도 안정적으로 진행하고 있다고 안내함. 수업 중 진도가 빠른 편이라 학원에서 많은 양을 풀고 가는 경우가 많아, 집 숙제가 상대적으로 적을 수 있다고 설명드림.\n\n현재 1학년 1학기 복습 교재와 1학년 2학기 진도 교재가 거의 마무리되어, 다음 주부터 2학년 1학기 새 교재와 1학년 2학기 복습 교재를 병행할 예정임. 여름방학 중 수업 시간은 기존대로 유지되며, 2학기에도 현재 반에서 큰 변동 없이 이어갈 가능성이 높다고 안내함.','\n',char(10)),'','2026-06-16 06:58:55');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781688372760','seed_kj_mwf_p1_01','2026-06-08','학습','결석 보충안내 관련 간단한 상담.','','2026-06-17 09:26:12');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781690119264','seed_kj_ttf_p2_06','2026-06-17','학습',replace('원과 부채꼴 5번째 재시 진행중.\n방정식활용 안되어 월수 계속 보충 진행중. \n오다안오다하다보니 한달이상 진행중이라 본인도 힘들거라고 전함.\n조만간 마무리될 예정. 보충 상황 안내.','\n',char(10)),'','2026-06-17 09:55:19');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781690253909','seed_kj_mwf_p3_04','2026-06-15','학습',replace('일단 오늘부터 한달 휴원예상.\n인대가 두개가 끊어져서 이번주는 입원이고, 퇴원하더라도 집이멀어 오고가기 힘들어 당분간은 휴원해야할것 같다고. 시험끝나고는 복귀하는게 목표.','\n',char(10)),'답지 줘서 보냈고, 어려운문제 스스로공부하다 찍어보낼수 있게 하겠다고 전함.','2026-06-17 09:57:33');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781690369404','seed_kj_mwf_p3_02','2026-06-10','학습',replace('중간고사 시험 성적관련.\n크게 문제는 없고 간단한 고등 관련 정보전달.\n앞으로도 시험이 어려울거라 예상되니 최대한 어려운문항 노출 많이되게 하겠다고 전달.','\n',char(10)),'','2026-06-17 09:59:29');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781690453234','seed_kj_mwf_p1_03','2026-06-10','학습',replace('언제나 행복이 충만하여 학원에서도 큰 문제는 없음.\n본인스스로도 만족도가 높아.\n다만 걱정은 학교 시험이 쉬워 공부가 느슨할까 걱정이라고.\n왕운과 똑같이 시키겠다고 전달.','\n',char(10)),'','2026-06-17 10:00:53');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781690609678','seed_kj_mwf_p1_02','2026-06-12','학습',replace('반은 당분간 바뀌는 거 없이 잘 케어해보겠다고 전함.\n학교에서도 지금 당장은 문제가 없으나 혹시 같이 있기 힘들시 바로 반을 바꿀 수 있게 조치하겠다고 전달함.\n본인도 지금 있는반을 좋아하니 일단 한번 지켜보자고 하심','\n',char(10)),'','2026-06-17 10:03:29');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781700928793','s26','2026-06-17','학습',replace('지혁이 어머니께서 태권도 시간인데 연락이 되지 않아 학원에 있는지 확인차 연락 주심. 지혁이는 휴대폰을 과학 선생님께 맡긴 상태였고, 원래 내일 오기로 했으나 본인이 9시 30분까지 더 하고 가겠다고 하여 학원에서 추가 학습 후 귀가함.\n\n지혁이는 숙제를 거의 해오지 않는 편이라 현재는 집에서 혼자 진행하기보다 학원에 일찍 오거나 추가로 불러서 학습을 시키고 있음. 혼자 공부하는 습관이 아직 잡히지 않아 중등 과정은 어느 정도 따라갈 수 있어도, 고등학교 진학 후에는 문제가 될 수 있어 지속적인 관리가 필요하다고 상담함.\n\n가정에서는 사춘기 영향으로 숙제 문제를 직접 강하게 부딪히기보다, 수학 관련 부분은 학원에서 최대한 불러서 관리하기로 함. 이번 주 토요일도 11시부터 3시까지 추가 학습을 안내했고, 월수금 등원 시에도 가능한 범위에서 더 시키며 중간 이상은 갈 수 있도록 관리하기로 함.','\n',char(10)),'','2026-06-17 12:55:28');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781700953066','s08','2026-06-17','학습',replace('쌍둥이 중 지우는 수학적으로 지율이보다 조금 더 나은 편이며, 특히 1학년 2학기 도형 단원을 비교적 잘 받아들이고 오답도 적은 편이라고 상담함. 현재 반에서 다소 편하게 느끼는 모습이 있어, 더 잘하는 친구들과 경쟁할 수 있도록 한 단계 위 반 이동도 고려했으나 지우 본인은 이동을 원하지 않는다고 함.\n\n반 이동 시 영어 수업 이후 화목 6시 30분 반으로 가야 하는 일정 부담이 있어, 현재는 무리하게 옮기기보다 상황을 더 지켜보기로 함. 쌍둥이라고 반드시 같은 반에 있을 필요는 없지만, 지우의 의사와 전체 일정도 함께 고려할 필요가 있다고 안내함.\n\n지율이는 본인이 수학 외에는 지우보다 더 낫다고 이야기하지만, 수학에서는 지우보다 오답이 많은 편으로 보임. 두 학생 모두 현재 학습 흐름과 반 적응 상태를 지켜보며, 필요 시 추후 반 조정이나 추가 관리 방향을 다시 상담하기로 함.','\n',char(10)),'','2026-06-17 12:55:53');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781700976963','s07','2026-06-17','학습',replace('쌍둥이 중 지우는 수학적으로 지율이보다 조금 더 나은 편이며, 특히 1학년 2학기 도형 단원을 비교적 잘 받아들이고 오답도 적은 편이라고 상담함. 현재 반에서 다소 편하게 느끼는 모습이 있어, 더 잘하는 친구들과 경쟁할 수 있도록 한 단계 위 반 이동도 고려했으나 지우 본인은 이동을 원하지 않는다고 함.\n\n반 이동 시 영어 수업 이후 화목 6시 30분 반으로 가야 하는 일정 부담이 있어, 현재는 무리하게 옮기기보다 상황을 더 지켜보기로 함. 쌍둥이라고 반드시 같은 반에 있을 필요는 없지만, 지우의 의사와 전체 일정도 함께 고려할 필요가 있다고 안내함.\n\n지율이는 본인이 수학 외에는 지우보다 더 낫다고 이야기하지만, 수학에서는 지우보다 오답이 많은 편으로 보임. 두 학생 모두 현재 학습 흐름과 반 적응 상태를 지켜보며, 필요 시 추후 반 조정이나 추가 관리 방향을 다시 상담하기로 함.','\n',char(10)),'','2026-06-17 12:56:17');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781758604964','seed_kj_ttf_p2_03','2026-06-08','학습','결석관련 보충일정안내 및 진도관련 상담.','','2026-06-18 04:56:45');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781758726689','seed_kj_mwf_p1_04','2026-06-01','학습','지후 합창대회 일정 결석관련 보충안내+진도상담','','2026-06-18 04:58:46');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781758868926','seed_kj_mwf_p1_05','2026-05-22','학습',replace('누나와는 다르게 해야할 때는 확실히 하는 편. \n안되면 계속 시키는걸 싫어해서 해야할 때는 확실하게 하는 성격. \n누나 상담하면서 간단한 진도안내+성향 다시한번 체크함.','\n',char(10)),'','2026-06-18 05:01:08');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781758954017','s_1778650158455','2026-05-22','학습',replace('수학이 워낙 약하고 스스로 하려는 의지가 없어.\n숙제를 첫날부터 안해와 부득이하게 9시 넘어서 보내야했음. \n앞으로도 계속 늦게보내도 상관없고, 스스로 안하기에 그냥 다 마무리시켜 보내주시라 부탁. \n계속적인 반복학습이 필요.','\n',char(10)),'','2026-06-18 05:02:34');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781759160405','seed_kj_ttf_p1_05','2026-05-21','학습',replace('학교에서 담임과의 문제가 있었음. \n계속적인 지각으로 상담시 버릇없이 행동하여 학교를 그만두겠다는 말까지 나와. 지각의 핑계로 학원숙제를 언급하여 체크하려 연락하심. \n성적은 잘나와 걱정이 없는데 버릇없이 행동시 강력히 혼내주시길 바람.','\n',char(10)),'','2026-06-18 05:06:00');
INSERT INTO "consultations" ("id","student_id","date","type","content","next_action","created_at") VALUES('cns_1781759268914','seed_kj_ttf_p1_05','2026-06-04','학습','수학 숙제를 안해와. 반전체의 약속이기에 마무리지어 보내려면 한참 늦어질 것 같다고 전달. 가족 저녁약속이 있으나 예준이만 뒤늦게 합류하게 하겠다고 하심.','','2026-06-18 05:07:48');
