INSERT INTO "daily_journals" ("id","date","teacher_name","content","status","feedback","created_at","updated_at") VALUES('jou_1780615289096','2026-06-04','박준성',replace('[AP Math 운영 일지 - 2026-06-04]\n작성자: 박준성\n\n■ 중1A반\n- 출석: 6/6\n- 숙제: 6/6\n- 진도:\n  * 개념유형 1-2 입체도형의성질-입체도형의 겉넓이 부피\n\n■ 중1C반\n- 출석: 3/3\n- 숙제: 3/3\n- 진도:\n  * 개념유형 1-2 기본도형-작도와합동\n- 상담:\n  * 허홍\n    신입상담\n    시범수업 후 담임인사.\n    홍이가 자기 수준을 알고 공부를 열심히 하는 계기가 생기면 좋겠다고 하심\n  \n■ 중3A반\n- 출석: 5/5\n- 숙제: 5/5\n- 진도:\n  * 수학의바이블 공통수학1 개념on: 이차부등식\n- 상담:\n  * 유채민\n    채민이 어머니께 연락드려 오늘 반 친구들 대부분이 순천대학교 축제 참석으로 결석 예정이라, 채민이도 오늘은 쉬고 반 전체 보강을 추후 별도로 잡아 진행하기로 안내함.\n    \n    최근 왕운중 수학 시험이 전반적으로 어렵게 출제되고 있으며, 학교 평균도 낮아진 상황을 설명드림. 특히 중간에 고난도 문항이 배치되어 학생들이 체감 난도가 높았고, 앞으로는 학교 출제 경향에 맞춰 고등 모의고사 유형까지 포함해 대비를 강화할 예정임.\n    \n    어머니께서는 채민이가 수학에 조금 더 욕심을 가졌으면 한다고 말씀하심. 이에 현재 시점에서 지나친 부담보다는 영수 기본기를 유지하면서 고등 진학 전 겨울방학부터 집중적으로 끌어올리는 방향이 중요하다고 안내함. 고등 진학 후 첫 시험 대비가 중요하므로 이후 학습 태도와 욕심을 조금씩 잡아가기로 함.\n','\n',char(10)),'제출완료','','2026-06-04 23:21:29','2026-06-04 23:21:29');
